(*
  Coq port of the finite probe-refined data certificate from
  PowerTowers/A198683/N12/N12Probe.lean.

  The n = 12 strict labels below are generated from the
  strict_class column of Combinatorics/ExpressionEnumeration/PowerTowers/Research/A198683/data/a198683-n12-candidates.tsv.
  The class-count certificate uses one representative row for each normalized
  class label, plus a range check that excludes any extra labels.
*)

From Stdlib Require Import Arith.PeanoNat.
From Stdlib Require Import Bool.Bool.
From Stdlib Require Import Lists.List.

Import ListNotations.
Set Implicit Arguments.
Open Scope nat_scope.
Set Warnings "-abstract-large-number".

Module LeanProofs.
Module A198683N12Probe.

Fixpoint allLabelsLt (bound : nat) (labels : list nat) : bool :=
  match labels with
  | [] => true
  | label :: rest => Nat.ltb label bound && allLabelsLt bound rest
  end.

Fixpoint allWitnessesLt (rows : nat) (witnesses : list nat) : bool :=
  match witnesses with
  | [] => true
  | witness :: rest => Nat.ltb witness rows && allWitnessesLt rows rest
  end.

Fixpoint classWitnessesOkFrom (labels : list nat) (class : nat)
    (witnesses : list nat) : bool :=
  match witnesses with
  | [] => true
  | witness :: rest =>
      Nat.eqb (nth witness labels 0) class &&
        classWitnessesOkFrom labels (S class) rest
  end.

Definition classWitnessesOk (labels witnesses : list nat) : bool :=
  classWitnessesOkFrom labels 0 witnesses.

Definition partitionCertificateOk (labels witnesses : list nat)
    (rows classes : nat) : bool :=
  Nat.eqb (length labels) rows &&
    Nat.eqb (length witnesses) classes &&
    allLabelsLt classes labels &&
    allWitnessesLt rows witnesses &&
    classWitnessesOk labels witnesses.

Fixpoint positionsWithLabelFrom (target idx : nat) (labels : list nat)
    : list nat :=
  match labels with
  | [] => []
  | label :: rest =>
      if Nat.eqb label target then
        idx :: positionsWithLabelFrom target (idx + 1) rest
      else
        positionsWithLabelFrom target (idx + 1) rest
  end.

Definition positionsWithLabel (target : nat) (labels : list nat) : list nat :=
  positionsWithLabelFrom target 0 labels.

